      days31To60Minor
      days61To90Minor
      daysOver90Minor
      totalOpenMinor
    }
    rows {
      customerId
      customerName
      buckets {
        currentMinor
        days1To30Minor
        days31To60Minor
        days61To90Minor
        daysOver90Minor
        totalOpenMinor
